import { useState } from 'react';

const Navbar = () => {
  const scrollToId = (id) => {
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const handleAuth = () => {
    // Trigger auth - could open modal or navigate
    window.location.href = '/auth';
  };
  const [isOpen, setIsOpen] = useState(false);

  return (
    <nav className="bg-white shadow-sm border-b border-gray-200 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          {/* Logo */}
          <div className="flex items-center">
<button onClick={() => scrollToId('home')} className="text-xl font-bold bg-transparent border-none p-0 cursor-pointer hover:opacity-80">
              Research<span className="text-teal-600">Mate</span> AI
            </button>
          </div>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center space-x-8">
<button onClick={() => scrollToId('home')} className="text-gray-700 hover:text-teal-600 font-medium transition-colors duration-200 bg-transparent border-none p-0 cursor-pointer">
              Home
            </button>
            <button onClick={() => scrollToId('features')} className="text-gray-700 hover:text-teal-600 font-medium transition-colors duration-200 bg-transparent border-none p-0 cursor-pointer">
              Features
            </button>
            <button onClick={() => scrollToId('pricing')} className="text-gray-700 hover:text-teal-600 font-medium transition-colors duration-200 bg-transparent border-none p-0 cursor-pointer">
              Pricing
            </button>
            <button onClick={() => scrollToId('contact')} className="text-gray-700 hover:text-teal-600 font-medium transition-colors duration-200 bg-transparent border-none p-0 cursor-pointer">
              Contact
            </button>
          </div>

          {/* Sign In Button */}
          <div className="hidden md:flex items-center">
            <button 
              onClick={handleAuth}
              className="bg-teal-600 text-white px-6 py-2 rounded-lg font-medium hover:bg-teal-700 transition-all duration-200 shadow-sm hover:shadow-md"
            >
              Sign In
            </button>
          </div>

          {/* Mobile menu button */}
          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="text-gray-700 hover:text-teal-600 focus:outline-none"
            >
              <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-white border-t border-gray-200">
          <div className="px-4 pt-2 pb-3 space-y-1 sm:px-3">
            <button onClick={() => scrollToId('home')} className="block px-3 py-2 text-gray-700 hover:text-teal-600 font-medium w-full text-left bg-transparent border-none p-0 cursor-pointer">
              Home
            </button>
            <button onClick={() => scrollToId('features')} className="block px-3 py-2 text-gray-700 hover:text-teal-600 font-medium w-full text-left bg-transparent border-none p-0 cursor-pointer">
              Features
            </button>
            <button onClick={() => scrollToId('pricing')} className="block px-3 py-2 text-gray-700 hover:text-teal-600 font-medium w-full text-left bg-transparent border-none p-0 cursor-pointer">
              Pricing
            </button>
            <button onClick={() => scrollToId('contact')} className="block px-3 py-2 text-gray-700 hover:text-teal-600 font-medium w-full text-left bg-transparent border-none p-0 cursor-pointer">
              Contact
            </button>
            <button 
              onClick={handleAuth}
              className="block px-3 py-2 text-teal-600 font-medium border border-teal-600 rounded-lg hover:bg-teal-50 mt-2 w-full text-left bg-transparent"
            >
              Sign In
            </button>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
